const now = new Date();
return [
  {
    json: {
      execution_id: `exec_${now.getFullYear()}${String(now.getMonth()+1).padStart(2,'0')}${String(now.getDate()).padStart(2,'0')}_${String(now.getHours()).padStart(2,'0')}${String(now.getMinutes()).padStart(2,'0')}${String(now.getSeconds()).padStart(2,'0')}`,
      workflow_name: 'Competitive Analysis',
      timestamp: now.toISOString(),
      timestamp_readable: now.toLocaleString('en-NO', { timeZone: 'Europe/Oslo' }),
      niches: ['romance', 'thriller', 'self-help', 'business', 'cooking']
    }
  }
];

const item = $input.first().json;
const context = $input.all()[0].json;

const saturation = (item.competitors_count / 100000) * 100;
const opportunity = saturation < 40 && item.search_volume > 3000 ? '🎯 Opportunity' : '';

return {
  A: context.timestamp_readable,
  B: item.niche,
  C: item.competitor_name || '',
  D: item.book_title || '',
  E: item.reviews || 0,
  F: item.rating || 0,
  G: item.price || '$0.00',
  H: Math.round(saturation * 10) / 10,
  I: opportunity,
  J: context.execution_id
};

